#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e5+5;
ll n,m,c[MAXN],t;
int main(void)
{
    n=read(),m=read();
    FOR(i,1,2*m)
    {
        ++c[read()];
    }
    ll sum=0;
    FOR(i,1,n)
    {
        sum+=c[i]*(c[i]-1)/2;
    }
    write(sum);
    return false;
}
